SELECT 
  FROM emp.tn_emp_acft a
 WHERE a.emp_plan_id = #{empPlanId}
   AND a.acft_sn     = #{sn}
   AND NOW() BETWEEN a.use_bgng_dt AND a.use_end_dt

SELECT COALESCE(MAX(acft_sn), 0) + 1
  FROM emp.tn_emp_acft
 WHERE emp_plan_id = #{empPlanId}

mapper.update:
UPDATE emp.tn_emp_acft
   SET acft_type_cd     = #{acftTypeCd},
       fuel_type_cd     = #{fuelTypeCd},
       acft_cnt         = #{acftCnt},
       rmrk             = #{rmrk},
       last_chg_dt      = NOW(),
       last_chg_user_id = #{lastChgUserId}
 WHERE emp_plan_id = #{empPlanId}
   AND acft_sn     = #{acftSn}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

UPDATE emp.tn_emp_acft
   SET use_end_dt       = NOW() - INTERVAL '1 minute',
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE emp_plan_id = #{empPlanId}
   AND acft_sn     = #{sn}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
